import { useParams } from "react-router-dom";
import products from "../data/products";

function ProductPage() {
  const { name } = useParams();
  const decodedName = decodeURIComponent(name);
  const product = products.find((p) => p.name === decodedName);

  if (!product) {
    return (
      <div className="productPage">
        <h1>Product not found</h1>
      </div>
    );
  }

  const lowestPrice = Math.min(...product.stores.map((s) => s.price));
  const highestPrice = Math.max(...product.stores.map((s) => s.price));
  const bestStore = product.stores.find((s) => s.price === lowestPrice);
  const savings = highestPrice - lowestPrice;

  return (
    <div className="productPage">

      {/* TOP SECTION */}
      <div className="productHero">

        <div className="productImageBox">
          <img
            src={product.image}
            alt={product.name}
            className="productMainImage"
          />
        </div>

        <div className="productInfoBox">
          <h1>{product.name}</h1>
          <h3>⭐ {product.rating} / 5</h3>
          <p className="reviewCount">{product.reviews} customer reviews</p>

          <div className="trustBadges">
            <span>✔ Verified product</span>
            <span>✔ Trusted comparison</span>
            <span>✔ Updated prices</span>
          </div>

          <div className="bestDealBox">
            <h2>Best Deal: {bestStore.site}</h2>
            <p className="bestPrice">₹{lowestPrice}</p>
            <p className="saveText">
              You save ₹{savings} compared to highest price
            </p>
          </div>

        </div>

      </div>

      {/* PRICE COMPARISON */}
      <div className="comparisonSection">
        <h2>Price Comparison</h2>

        <div className="comparisonTable">

          <div className="comparisonHeader">
            <span>Store</span>
            <span>Price</span>
            <span>Rating</span>
            <span>Action</span>
          </div>

          {product.stores.map((s, i) => (
            <div className="store" key={i}>
              <span>{s.site}</span>

              <span>₹{s.price}</span>

              <span>⭐ {s.rating}</span>

              <span>
                {s.price === lowestPrice ? (
                  <button className="buyBtn">Buy Now</button>
                ) : (
                  <button className="cartBtn">Add to Cart</button>
                )}
              </span>
            </div>
          ))}

        </div>
      </div>

      {/* TRUST SECTION */}
      <div className="reviewSection">
        <h2>Why choose this product?</h2>

        <div className="reviewGrid">

          <div className="reviewCard">
            <h3>Strong Rating</h3>
            <p>
              This product has a solid rating of {product.rating} out of 5.
            </p>
          </div>

          <div className="reviewCard">
            <h3>User Reviews</h3>
            <p>
              {product.reviews} users reviewed this product.
            </p>
          </div>

          <div className="reviewCard">
            <h3>Smart Comparison</h3>
            <p>
              Compare prices across multiple platforms before buying.
            </p>
          </div>

        </div>
      </div>

    </div>
  );
}

export default ProductPage;
